    svg: `<svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 24 24"><path fill="#1f6b46" fill-rule="evenodd" d="M3 2.8 L7 3.9 Q12 6.4 17 3.9 L21 2.8 L21.5 9.5 Q21.5 21.5 12 21.5 Q2.5 21.5 2.5 9.5 Z M8 10.7 m2.9 0 a2.9 2.9 0 1 1 -5.8 0 a2.9 2.9 0 1 1 5.8 0 Z M16 10.7 m2.9 0 a2.9 2.9 0 1 1 -5.8 0 a2.9 2.9 0 1 1 5.8 0 Z M12 13.8 L14.6 16.8 L12 19.8 L9.4 16.8 Z"/></svg>`,
